public boolean twoTwo(int[] nums) {
    if (nums == null || nums.length == 0) {
        return true; // edge case: empty array
    }

    boolean prevIsTwo = false;

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 2) {
            if (i > 0 && nums[i - 1] == 2) {
                prevIsTwo = true;
            } else if (i < nums.length - 1 && nums[i + 1] == 2) {
